# GridUnion namespace naming conventions
# Enforced by CI validation on every DDL statement

ALLOWED_SCHEMA_PATTERNS = {
    'bronze':   r'^bronze_(de|fr|nl|lu)$',           # bronze_{country}
    'silver':   r'^silver_(de|fr|nl|lu)$',           # silver_{country}
    'gold':     r'^gold_[a-z_]+$',                    # gold_{domain}
    'platinum': r'^platinum_[a-z_]+$',                # platinum_{domain}
    'state':    r'^state$',                           # pipeline state tables
    'monitoring': r'^monitoring$',                    # platform metrics
}

ALLOWED_TABLE_PATTERNS = {
    # Tables use snake_case, no abbreviations, no version numbers
    'general': r'^[a-z][a-z0-9_]{2,60}$',
    # Prohibited patterns (caught by CI)
    'prohibited': [
        r'_v\d+$',           # no version suffixes (meter_readings_v2)
        r'_final$',          # no _final suffix
        r'_temp$',           # no _temp (use transient schemas instead)
        r'_backup$',         # no _backup (use Delta time travel)
        r'^tmp_',            # no tmp_ prefix
    ],
}

def validate_fully_qualified_name(fqn: str) -> list[str]:
    """Validate a catalog.schema.table name against GridUnion conventions.

    Returns a list of violation messages (empty = valid).
    """
    parts = fqn.split('.')
    violations = []

    if len(parts) != 3:
        violations.append(f"Expected 3 parts (catalog.schema.table), got {len(parts)}")
        return violations

    catalog, schema, table = parts

    # Catalog must be one of the three environments
    if catalog not in ('gridunion_prod', 'gridunion_staging', 'gridunion_dev'):
        violations.append(f"Invalid catalog: {catalog}")

    # Schema must match one of the allowed patterns
    import re
    schema_valid = any(
        re.match(pattern, schema) 
        for pattern in ALLOWED_SCHEMA_PATTERNS.values()
    )
    if not schema_valid:
        violations.append(f"Invalid schema: {schema}")

    # Table must match general pattern and not match prohibited patterns
    if not re.match(ALLOWED_TABLE_PATTERNS['general'], table):
        violations.append(f"Invalid table name: {table}")
    for prohibited in ALLOWED_TABLE_PATTERNS['prohibited']:
        if re.search(prohibited, table):
            violations.append(f"Prohibited table name pattern: {table} matches {prohibited}")

    return violations

-- Unity Catalog access control for the German Silver schema
-- Only the German DE team can write; everyone else reads

-- Owner team: full access
GRANT ALL PRIVILEGES ON SCHEMA gridunion_prod.silver_de TO `de_germany_team`;

-- Consumer teams: read-only
GRANT SELECT ON SCHEMA gridunion_prod.silver_de TO `analytics_team`;
GRANT SELECT ON SCHEMA gridunion_prod.silver_de TO `ml_team`;
GRANT SELECT ON SCHEMA gridunion_prod.silver_de TO `de_france_team`;  -- cross-country reads

-- Regulatory team: read-only on country-specific schemas
GRANT SELECT ON SCHEMA gridunion_prod.silver_de TO `regulatory_de_team`;
GRANT SELECT ON SCHEMA gridunion_prod.gold_regulatory TO `regulatory_de_team`;
-- Note: regulatory_de_team has NO access to silver_fr, silver_nl, silver_lu

-- Platform team: admin access for maintenance
GRANT ALL PRIVILEGES ON CATALOG gridunion_prod TO `platform_admin_team`;

// Custom optimizer rules are written in Scala (not PySpark) because they
// extend Catalyst's internal API. They are packaged as a JAR and loaded
// via spark.sql.extensions.

import org.apache.spark.sql.SparkSession
import org.apache.spark.sql.catalyst.plans.logical._
import org.apache.spark.sql.catalyst.rules.Rule
import org.apache.spark.sql.catalyst.expressions._

/**
 * Injects a country filter into scans on country-segmented Silver schemas.
 * 
 * When a query reads from silver_de.meter_readings without a country filter,
 * this rule adds Filter(country = 'DE') above the scan. This ensures partition
 * pruning on the country partition column even if the engineer's query omits it.
 */
object InjectCountryFilter extends Rule[LogicalPlan] {
  override def apply(plan: LogicalPlan): LogicalPlan = plan transform {
    case scan: LogicalRelation 
      if isCountrySegmentedTable(scan) && !hasCountryFilter(plan, scan) =>
      val countryCode = extractCountryFromSchema(scan)  // "de" from silver_de
      val countryFilter = EqualTo(
        UnresolvedAttribute("country"),
        Literal(countryCode.toUpperCase)
      )
      Filter(countryFilter, scan)
  }

  private def isCountrySegmentedTable(scan: LogicalRelation): Boolean = {
    val tableName = scan.catalogTable.map(_.identifier.toString).getOrElse("")
    tableName.matches(".*\\.(silver|bronze)_(de|fr|nl|lu)\\..*")
  }

  private def hasCountryFilter(plan: LogicalPlan, scan: LogicalRelation): Boolean = {
    // Walk up the plan tree to check if a country filter already exists
    plan.find {
      case Filter(condition, _) => condition.references.exists(_.name == "country")
      case _ => false
    }.isDefined
  }

  private def extractCountryFromSchema(scan: LogicalRelation): String = {
    val schema = scan.catalogTable.map(_.identifier.database.getOrElse("")).getOrElse("")
    schema.split("_").last  // silver_de -> de
  }
}

// The DataSource V2 API for pushdown negotiation
// The data source declares which predicates it can handle

import org.apache.spark.sql.connector.read._
import org.apache.spark.sql.sources._

/**
 * A ScanBuilder that supports predicate pushdown.
 * 
 * Catalyst calls pushFilters() with the decomposed predicates.
 * The source returns which ones it can handle (pushed) and which
 * Spark must evaluate post-scan (not pushed).
 */
class GridUnionScanBuilder extends ScanBuilder with SupportsPushDownFilters {
  private var pushedFilters: Array[Filter] = Array.empty

  override def pushFilters(filters: Array[Filter]): Array[Filter] = {
    val (pushable, remaining) = filters.partition(canPush)
    this.pushedFilters = pushable
    remaining  // return the filters that could NOT be pushed
  }

  override def pushedFilters(): Array[Filter] = pushedFilters

  private def canPush(filter: Filter): Boolean = filter match {
    case EqualTo(_, _) => true
    case GreaterThan(_, _) => true
    case LessThan(_, _) => true
    case In(_, _) => true
    case IsNull(_) => true
    case IsNotNull(_) => true
    case And(left, right) => canPush(left) && canPush(right)
    case _ => false  // unsupported predicates are evaluated by Spark post-scan
  }
}

def check_backward_compatibility(
    old_schema: StructType, new_schema: StructType
) -> list[str]:
    """Check if new_schema is backward-compatible with old_schema.

    Backward compatible means: a reader using new_schema can read data
    written with old_schema without errors.

    Returns list of violation messages (empty = compatible).
    """
    violations = []
    old_fields = {f.name: f for f in old_schema.fields}
    new_fields = {f.name: f for f in new_schema.fields}

    # Check 1: No columns removed (old data has them, new reader must handle them)
    # Actually for backward compat, removing a column from the schema is OK
    # if the reader no longer needs it. The issue is ADDING a non-nullable column.

    # Check 2: New non-nullable columns must have defaults
    for name, field in new_fields.items():
        if name not in old_fields and not field.nullable:
            violations.append(
                f"New non-nullable column '{name}' added without default. "
                f"Old data will have null for this column, violating non-nullable."
            )

    # Check 3: Type changes must be widening (int->long OK, long->int NOT OK)
    SAFE_WIDENINGS = {
        ('IntegerType', 'LongType'),
        ('FloatType', 'DoubleType'),
        ('ShortType', 'IntegerType'),
        ('ShortType', 'LongType'),
    }
    for name in old_fields:
        if name in new_fields:
            old_type = type(old_fields[name].dataType).__name__
            new_type = type(new_fields[name].dataType).__name__
            if old_type != new_type:
                if (old_type, new_type) not in SAFE_WIDENINGS:
                    violations.append(
                        f"Column '{name}' type changed from {old_type} to {new_type}. "
                        f"Not a safe widening."
                    )

    # Check 4: Nullability cannot become stricter
    for name in old_fields:
        if name in new_fields:
            if old_fields[name].nullable and not new_fields[name].nullable:
                violations.append(
                    f"Column '{name}' changed from nullable to non-nullable. "
                    f"Old data may contain nulls."
                )

    return violations

def analyze_breaking_change_impact(
    spark, table_fqn: str, removed_columns: list[str]
) -> dict:
    """Analyze the downstream impact of removing columns from a table.

    Uses the contract registry and lineage graph to identify
    every consumer that references the affected columns.
    """
    # Load the contract to get registered consumers
    contract = load_contract_for_table(spark, table_fqn)
    consumers = contract.get('consumers', [])

    affected = []
    for consumer in consumers:
        columns_used = set(consumer.get('columns_used', []))
        overlap = columns_used.intersection(set(removed_columns))
        if overlap:
            affected.append({
                'team': consumer['team'],
                'columns_affected': list(overlap),
                'contact': consumer.get('contact', 'unknown'),
                'registered_since': consumer.get('since', 'unknown'),
            })

    # Also check the lineage graph for unregistered consumers
    lineage = spark.table('gridunion_prod.monitoring.lineage_graph')
    unregistered = (lineage
        .filter(col('source_table') == table_fqn)
        .filter(~col('consumer_team').isin(
            [c['team'] for c in consumers]
        ))
        .collect()
    )

    return {
        'table': table_fqn,
        'removed_columns': removed_columns,
        'registered_affected': affected,
        'unregistered_consumers': [
            {'team': r['consumer_team'], 'pipeline': r['consumer_pipeline']}
            for r in unregistered
        ],
        'total_affected': len(affected) + len(unregistered),
    }

from pyspark.sql.types import StructType
import json

def detect_schema_drift(
    spark, new_data_df, registered_schema: StructType, source_name: str
) -> dict:
    """Compare new data's inferred schema against the registered schema.

    Returns drift report with new columns, missing columns, and type changes.
    """
    actual_fields = {f.name: f for f in new_data_df.schema.fields}
    expected_fields = {f.name: f for f in registered_schema.fields}

    new_columns = [
        {'name': name, 'type': f.dataType.simpleString()}
        for name, f in actual_fields.items() if name not in expected_fields
    ]

    missing_columns = [
        {'name': name, 'type': f.dataType.simpleString()}
        for name, f in expected_fields.items() if name not in actual_fields
    ]

    type_changes = []
    for name in actual_fields:
        if name in expected_fields:
            actual_type = actual_fields[name].dataType.simpleString()
            expected_type = expected_fields[name].dataType.simpleString()
            if actual_type != expected_type:
                type_changes.append({
                    'name': name,
                    'expected_type': expected_type,
                    'actual_type': actual_type,
                })

    has_drift = bool(new_columns or missing_columns or type_changes)
    severity = 'none'
    if missing_columns or type_changes:
        severity = 'critical'  # blocks downstream processing
    elif new_columns:
        severity = 'warning'   # alerts but does not block

    report = {
        'source': source_name,
        'has_drift': has_drift,
        'severity': severity,
        'new_columns': new_columns,
        'missing_columns': missing_columns,
        'type_changes': type_changes,
    }

    if severity == 'critical':
        send_alert(f"CRITICAL schema drift on {source_name}: {json.dumps(report, indent=2)}")
        raise SchemaError(f"Schema drift detected on {source_name}. Blocking downstream.")
    elif severity == 'warning':
        send_alert(f"Schema drift warning on {source_name}: {len(new_columns)} new columns")

    log_drift_report(spark, report)
    return report

# GridUnion's speculation configuration by pipeline category

SPECULATION_CONFIGS = {
    'daily_batch': {
        # Dedicated cluster, homogeneous hardware, rare stragglers
        'spark.speculation': 'false',
    },
    'quarterly_reprocess': {
        # Shared cluster, long-running, straggler-prone
        'spark.speculation': 'true',
        'spark.speculation.multiplier': '1.5',  # 1.5x median triggers speculation
        'spark.speculation.quantile': '0.9',    # wait for 90% completion (conservative)
        'spark.speculation.interval': '1000ms',  # check every second
    },
    'streaming': {
        # Small batches, speculation overhead > benefit
        'spark.speculation': 'false',
    },
    'interactive_notebooks': {
        # Fast feedback desired, but shared cluster
        'spark.speculation': 'true',
        'spark.speculation.multiplier': '3.0',  # only speculate on extreme stragglers
        'spark.speculation.quantile': '0.75',
    },
}

# Apply in the pipeline's SparkSession creation
def create_session_with_speculation(config, category):
    builder = SparkSession.builder
    for key, value in SPECULATION_CONFIGS.get(category, {}).items():
        builder = builder.config(key, value)
    return builder.getOrCreate()

