-- GridUnion's privilege hierarchy
-- The platform_admin_team is the only group with catalog-level ALL PRIVILEGES
-- No individual user has direct privileges — all access flows through AAD groups

-- Catalog-level: only platform admin
GRANT ALL PRIVILEGES ON CATALOG gridunion_prod TO `platform_admin_team`;

-- Schema-level: each team gets USAGE + specific privileges
GRANT USAGE ON CATALOG gridunion_prod TO `de_germany_team`;
GRANT ALL PRIVILEGES ON SCHEMA gridunion_prod.silver_de TO `de_germany_team`;
GRANT SELECT ON SCHEMA gridunion_prod.gold_billing TO `de_germany_team`;

-- Escalation prevention: no team can grant privileges to other teams
-- Only platform_admin_team has the GRANT OPTION
-- This prevents the de_germany_team from granting silver_de access to the ml_team

-- Anti-pattern: direct user grants (prohibited by policy, audited weekly)
-- GRANT SELECT ON TABLE gridunion_prod.silver_de.meter_readings TO `user@gridunion.com`;
-- ^ This is detected by the weekly audit and escalated to the team lead for remediation
